<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Maze Exploration Game</title>
    <style>
        body {
            background: #222;
            color: #eee;
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
        }
        #maze {
            border: 2px solid #555;
            background: #000;
            line-height: 0;
        }
        canvas {
            display: block;
        }
        .ui {
            margin-bottom: 10px;
            font-size: 20px;
            display: flex;
            gap: 20px;
        }
        button {
            padding: 10px 20px;
            cursor: pointer;
            background: #444;
            color: white;
            border: 1px solid #666;
        }
        button:hover { background: #555; }
    </style>
</head>
<body>
    <div class="ui">
        <div>Completed: <span id="completed">0</span></div>
        <div>Timer: <span id="timer">0</span></div>
        <button id="reset">Reset Game</button>
    </div>
    <div id="maze">
        <canvas id="gameCanvas" width="400" height="400"></canvas>
    </div>

    <script>
        const ROWS = 21;
        const COLS = 21;
        const BOT_COUNT = 24;
        const CANVAS_SIZE = 400;

        function mulberry32(a) {
            return function() {
                var t = a += 0x6D2B79F5;
                t = Math.imul(t ^ (t >>> 15), t | 1);
                t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
                return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
            }
        }

        class Bot {
            constructor(id, r, c, seed) {
                this.r = r;
                this.c = c;
                this.prevR = r;
                this.prevC = c;
                this.path = [{r, c}];
                this.visited = new Set([`${r},${c}`]);
                this.stack = [];
                this.deadEnds = [];
                this.finishTick = null;

                const rng = mulberry32(seed + id);
                let dirs = [0, 1, 2, 3]; // N, E, S, W
                for (let i = dirs.length - 1; i > 0; i--) {
                    const j = Math.floor(rng() * (i + 1));
                    [dirs[i], dirs[j]] = [dirs[j], dirs[i]];
                }
                this.pref = dirs;
            }

            getNeighbors(maze) {
                const directions = [
                    {r: -1, c: 0}, // N
                    {r: 0, c: 1},  // E
                    {r: 1, c: 0},  // S
                    {r: 0, c: -1}  // W
                ];
                let neighbors = [];
                for (let i = 0; i < 4; i++) {
                    const d = directions[i];
                    const nr = this.r + d.r;
                    const nc = this.c + d.c;
                    if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS) {
                        const walls = maze.walls(nr, nc);
                        let hasWall = false;
                        if (d.r === -1) hasWall = walls.s;
                        else if (d.r === 1) hasWall = walls.n;
                        else if (d.c === 1) hasWall = walls.w;
                        else if (d.c === -1) hasWall = walls.e;

                        neighbors.push(hasWall ? null : {r: nr, c: nc});
                    } else {
                        neighbors.push(null);
                    }
                }
                return neighbors;
            }

            move(maze, currentTick, exit) {
                if (this.finishTick !== null) return;

                const neighbors = this.getNeighbors(maze);
                let options = [];
                for (let i = 0; i < 4; i++) {
                    if (neighbors[i] && !this.visited.has(`${neighbors[i].r},${neighbors[i].c}`)) {
                        options.push(i);
                    }
                }

                if (options.length > 0) {
                    let choice = -1;
                    for (let p of this.pref) {
                        if (options.includes(p)) {
                            choice = p;
                            break;
                        }
                    }
                    if (choice === -1) choice = options[0];

                    const next = neighbors[choice];
                    this.prevR = this.r;
                    this.prevC = this.c;
                    this.stack.push({r: this.r, c: this.c});
                    this.r = next.r;
                    this.c = next.c;
                    this.path.push({r: this.r, c: this.c});
                    this.visited.add(`${this.r},${this.c}`);

                    if (this.r === exit.r && this.c === exit.c) {
                        this.finishTick = currentTick;
                    }
                } else if (this.stack.length > 0) {
                    const prev = this.stack.pop();
                    this.deadEnds.push({r: this.r, c: this.c});
                    this.prevR = this.r;
                    this.prevC = this.c;
                    this.r = prev.r;
                    this.c = prev.c;
                    this.path.push({r: this.r, c: this.c});
                }
            }
        }

        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');
        let animationId;

        window.game = {
            size: {rows: ROWS, cols: COLS},
            spawn: {r: 0, c: 0},
            exit: {r: ROWS - 1, c: COLS - 1},
            elapsed: 0,
            bots: [],
            maze: null,
            allFinished: false,

            initMaze(seed) {
                const rng = mulberry32(seed);
                let grid = Array(ROWS).fill().map(() => Array(COLS).fill().map(() => ({n:true, e:true, s:true, w:true})));
                let visited = Array(ROWS).fill().map(() => Array(COLS).fill(false));

                function carve(r, c) {
                    visited[r][c] = true;
                    const dirs = [[-1,0], [0,1], [1,0], [0,-1]]; // N, E, S, W
                    let shuffled = [0, 1, 2, 3].sort(() => rng() - 0.5);

                    for (let i of shuffled) {
                        const [dr, dc] = dirs[i];
                        const nr = r + dr;
                        const nc = c + dc;
                        if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS && !visited[nr][nc]) {
                            if (i === 0) { grid[r][c].n = false; grid[nr][nc].s = false; }
                            else if (i === 1) { grid[r][c].e = false; grid[nr][nc].w = false; }
                            else if (i === 2) { grid[r][c].s = false; grid[nr][nc].n = false; }
                            else if (i === 3) { grid[r][c].w = false; grid[nr][nc].e = false; }
                            carve(nr, nc);
                        }
                    }
                }
                carve(0, 0);
                this.maze = grid;
            },

            reset(seed = 12345) {
                if (animationId) cancelAnimationFrame(animationId);
                this.initMaze(seed);
                this.bots = [];
                for (let i = 0; i < BOT_COUNT; i++) {
                    this.bots.push(new Bot(i, this.spawn.r, this.spawn.c, seed));
                }
                this.elapsed = 0;
                this.allFinished = false;
                this.render();
            },

            tick(n) {
                for (let i = 0; i < n; i++) {
                    this.update();
                }
            },

            update() {
                let anyMoving = false;
                for (let bot of this.bots) {
                    if (bot.finishTick === null) {
                        bot.move(this.maze, this.elapsed + 1, this.exit);
                        anyMoving = true;
                    }
                }

                if (anyMoving && !this.allFinished) {
                    this.elapsed++;
                    if (this.bots.every(b => b.finishTick !== null)) {
                        this.allFinished = true;
                    }
                }
            },

            walls(r, c) {
                return this.maze[r][c];
            },

            render() {
                ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
                const cellW = CANVAS_SIZE / COLS;
                const cellH = CANVAS_SIZE / ROWS;

                // Draw Maze
                for (let r = 0; r < ROWS; r++) {
                    for (let c = 0; c < COLS; c++) {
                        const walls = this.maze[r][c];
                        ctx.strokeStyle = "#555";
                        ctx.lineWidth = 2;
                        if (walls.n) ctx.beginPath(), ctx.moveTo(c * cellW, r * cellH), ctx.lineTo((c + 1) * cellW, r * cellH), ctx.stroke();
                        if (walls.e) ctx.beginPath(), ctx.moveTo((c + 1) * cellW, r * cellH), ctx.lineTo((c + 1) * cellW, (r + 1) * cellH), ctx.stroke();
                        if (walls.s) ctx.beginPath(), ctx.moveTo(c * cellW, (r + 1) * cellH), ctx.lineTo((c + 1) * cellW, (r + 1) * cellH), ctx.stroke();
                        if (walls.w) ctx.beginPath(), ctx.moveTo(c * cellW, r * cellH), ctx.lineTo(c * cellW, (r + 1) * cellH), ctx.stroke();
                    }
                }

                // Draw Exit
                ctx.fillStyle = "#f00";
                ctx.fillRect(this.exit.c * cellW + 4, this.exit.r * cellH + 4, cellW - 8, cellH - 8);

                // Draw Bots
                for (let bot of this.bots) {
                    const color = `hsl(${bot.id * (360 / BOT_COUNT)}, 70%, 50%)`;
                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(bot.r * cellW + cellW/2, bot.c * cellH + cellH/2, cellW/4, 0, Math.PI * 2);
                    ctx.fill();
                }

                document.getElementById('completed').innerText = this.bots.filter(b => b.finishTick !== null).length;
                document.getElementById('timer').innerText = this.elapsed;
            }
        };

        // Animation Loop for Smooth Movement
        let lastTime = 0;
        function animate(time) {
            const dt = time - lastTime;
            lastTime = time;

            const cellW = CANVAS_SIZE / COLS;
            const cellH = CANVAS_SIZE / ROWS;

            window.game.bots.forEach(bot => {
                if (bot.finishTick === null) {
                    // Simple interpolation for smooth visual movement
                    const lerpFactor = Math.min(1, dt / 30); // Target ~30fps interpolation
                    const curX = bot.prevC + (bot.c - bot.prevC) * lerpFactor;
                    const curY = bot.prevR + (bot.r - bot.prevR) * lerpFactor;

                    // We need to draw the interpolated position, but we can't easily 
                    // modify the bot object without breaking tick determinism.
                    // So we use a temporary visual state or just redraw everything.
                }
            });

            // To keep it simple and smooth while maintaining deterministic ticks:
            // We will draw bots at their current logical positions, but since 
            // tick(n) is synchronous, the "smoothness" comes from the fact that 
            // we can call tick(1) every frame.
            window.game.render();
            animationId = requestAnimationFrame(animate);
        }

        document.getElementById('reset').addEventListener('click', () => window.game.reset());

        // Start game
        window.game.reset();

        // Run simulation at 30 ticks per second (or as fast as possible)
        setInterval(() => {
            window.game.tick(1);
        }, 33);

        // The animation loop handles the rendering of the current state.
        animate(0);

    </script>
</body>
</html>
